Utility = {}

Utility.dayTime = 1 * 24 * 60 * 60

local function getDir(yaw)
    while(yaw >= 360)
    do
        yaw = yaw - 360
    end

    if yaw == 0 then
        return VectorUtil.newVector3(0, 0, 1)
    elseif yaw == 90 then
        return VectorUtil.newVector3(-1, 0, 0)
    elseif yaw == 180 then
        return VectorUtil.newVector3(0, 0, -1)
    elseif yaw == 270 then
        return VectorUtil.newVector3(1, 0, 0)
    end

    if yaw < 90 then
        local rad = math.rad(yaw)
        return VectorUtil.newVector3(-math.sin(rad), 0, math.cos(rad))
    elseif yaw < 180 then
        yaw = yaw - 90
        local rad = math.rad(yaw)
        return VectorUtil.newVector3(-math.cos(rad), 0, -math.sin(rad))
    elseif yaw < 270 then
        yaw = yaw - 180
        local rad = math.rad(yaw)
        return VectorUtil.newVector3(math.sin(rad), 0, -math.cos(rad))
    elseif yaw < 360 then
        yaw = yaw - 270
        local rad = math.rad(yaw)
        return VectorUtil.newVector3(math.cos(rad), 0, math.sin(rad))
    end

    return VectorUtil.newVector3(0, 0, 1)
end

function Utility.trimTailZero(str)
    local loopCount = 1
    while str:sub(str:len(), str:len()) == "0" do
        if loopCount >= 10 then
            break
        end

        str = str:sub(1, str:len() - 1)

        loopCount = loopCount + 1
    end
    return str
end

--数字转为“K”、“M”、“B”格式
function Utility.toKMBString(str, precision)
    str = tostring(BigNum.new(str))
    precision = precision or 0
    local len = string.len(str)

    if str == "inf" or str == "Inf" then
        return "∞"
    end

    for _, setting in pairs(UnitConfig.settings) do
        if len > setting.digitNum then
            local integer = string.sub(str, 1, len - setting.digitNum) --整数部分
            local decimal = string.sub(str, len - setting.digitNum + 1, len - setting.digitNum + precision) --小数部分
            decimal = Utility.trimTailZero(decimal)
            if precision ~= 0 then
                if decimal ~= "" then
                    str = integer .. "." .. decimal .. setting.abbreviation
                else
                    str = integer .. setting.abbreviation
                end
            else
                str = integer .. setting.abbreviation
            end
            return str
        end
    end

    return str
end

function Utility.checkQuanJiRange(attacker, target, enemyRadius)
    enemyRadius = enemyRadius or GameConfig.enemyRadius

    if attacker == nil or target == nil then
        return false
    end

    local pos1 = attacker:getPosition()
    local pos2 = target:getPosition()

    if MathUtil:distanceSquare2d(pos1, pos2) >= math.pow(attacker.radius * ClientConfig.adjustCoe + enemyRadius, 2) then
        return false
    end

    local dir1 = getDir(attacker:getRotationYaw()) --攻击者朝向
    local dir2 = VectorUtil.newVector3(pos2.x - pos1.x, pos2.y - pos1.y, pos2.z - pos1.z)

    local dot = dir1.x * dir2.x + dir1.z * dir2.z
    if dot <= 0 then
        return false
    end

    return true
end

--获取玩家朝向
function Utility.getPlayerDir(player)
    if player == nil then
        return
    end

    local yaw = player.entityPlayerMP.rotationYaw
    return getDir(yaw)
end

