function Utility.playEffect(id, pos, scale)
    local config = EffectConfig:getEffectConfig(id)
    if not config then
        return
    end
    pos = pos or VectorUtil.newVector3(config.effectPos[1], config.effectPos[2], config.effectPos[3])
    scale = scale or 1
    EngineWorld:addSimpleEffect(config.name, pos, config.effectYaw, config.liveTime, 0, config.scale * scale)
end

function Utility.tableToString(tb)
    if type(tb) ~= "table" then
        return ""
    end

    local str = ""
    for i, v in pairs(tb) do
        str = str .. i .. "," .. v .. "#"
    end

    str = string.sub(str, 1, string.len(str) - 1)

    --print(string.format("Utility.tableToString %s %s", inspect.inspect(tb), str))

    return str
end

